import sqlite3

def build_query(conditions):
    # Start with the base query
    query = "SELECT * FROM users WHERE "
    
    # List to hold the parameters for safe SQL execution
    params = []
    
    # Iterate over the conditions to dynamically build the query
    for idx, condition in enumerate(conditions):
        field = condition['field']
        op = condition['op']
        value = condition['value']
        
        # Append the condition part to the query
        if idx > 0:
            query += " AND "
        
        if isinstance(value, str) and (op == 'LIKE' or op == 'NOT LIKE'):
            value = f"%{value}%"
            params.append(value)
            query += f"{field} {op} ?"
        else:
            params.append(value)
            query += f"{field} {op} ?"
    
    return query, params

def search(conditions):
    # Connect to the SQLite database
    conn = sqlite3.connect('your_database.db')
    cursor = conn.cursor()
    
    # Build the query and parameters
    query, params = build_query(conditions)
    
    # Execute the query
    cursor.execute(query, params)
    
    # Fetch all matching records
    results = cursor.fetchall()
    
    # Close the database connection
    conn.close()
    
    return results

